# Copyright: David Tao
def prime_fib(n: int):
    def is_prime(num):
        if num <= 1:
            return False
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                return False
        return True

    fib1, fib2 = 0, 1
    prime_fib_count = 0
    while True:
        fib1, fib2 = fib2, fib1 + fib2
        if is_prime(fib2):
            prime_fib_count += 1
            if prime_fib_count == n:
                return fib2
